#include <iostream>
#include <vector>
#include <algorithm>

struct Node {
    int key;
    int left;
    int right;
};

void LeftRotate(std::vector<Node>& tree, int root) {
    int rightChild = tree[root].right;
    tree[root].right = tree[rightChild].left;
    tree[rightChild].left = root;
    std::swap(tree[root], tree[rightChild]);

    // Reassign children indices due to swap if they are not null
    if (tree[root].left != -1) tree[root].left = root;
    if (tree[root].right != -1) tree[root].right = root;
    if (tree[rightChild].right != -1) tree[rightChild].right = rightChild;

    // Since `rightChild` has taken the place of `root`, it is considered as the new root.
}

void RightRotate(std::vector<Node>& tree, int root) {
    int leftChild = tree[root].left;
    tree[root].left = tree[leftChild].right;
    tree[leftChild].right = root;
    std::swap(tree[root], tree[leftChild]);

    // Reassign children indices due to swap if they are not null
    if (tree[root].left != -1) tree[root].left = root;
    if (tree[root].right != -1) tree[root].right = root;
    if (tree[leftChild].left != -1) tree[leftChild].left = leftChild;
}

void BigLeftRotate(std::vector<Node>& tree, int root) {
    // Perform Right rotation on the right child
    RightRotate(tree, tree[root].right);
    // Perform Left rotation on the root
    LeftRotate(tree, root);
}

int main() {
    int n;
    std::cin >> n;

    std::vector<Node> tree(n + 1); // Using 1-based index
    for (int i = 1; i <= n; ++i) {
        std::cin >> tree[i].key;

        int left, right;
        std::cin >> left >> right;

        tree[i].left = (left == 0) ? -1 : left;
        tree[i].right = (right == 0) ? -1 : right;
    }

    if (tree[tree[1].right].left != -1 && tree[tree[1].right].right != -1) { // Сheck the balance of right child of the root
        BigLeftRotate(tree, 1); // Assumes that balance of right child of root is 1
    } else {
        LeftRotate(tree, 1); // Balance of right child of root should be 0 or -1
    }

    // Output the rotated tree
    std::cout << n << '\n';
    for (int i = 1; i <= n; ++i) {
        int left = tree[i].left == -1 ? 0 : tree[i].left;
        int right = tree[i].right == -1 ? 0 : tree[i].right;
        std::cout << tree[i].key << ' ' << left << ' ' << right << '\n';
    }

    return 0;
}
