#include <iostream>
#include <vector>
#include <algorithm>

struct Node {
    int key, height, id;
    Node *left, *right;
};

int height(Node* node) {
    if (node == nullptr) {
        return 0;
    }
    return node->height;
}

int getBalance(Node* node) {
    if (node == nullptr) {
        return 0;
    }
    return height(node->right) - height(node->left);
}

Node* newNode(int key, int id) {
    Node* node = new Node();
    node->key = key;
    node->height = 1;  // new node is initially added at leaf
    node->id = id;
    node->left = node->right = nullptr;
    return node;
}

Node* rightRotate(Node* y) {
    Node* x = y->left;
    Node* T2 = x->right;

    // Perform rotation
    x->right = y;
    y->left = T2;

    // Update heights
    y->height = std::max(height(y->left), height(y->right)) + 1;
    x->height = std::max(height(x->left), height(x->right)) + 1;

    // Return new root
    return x;
}

Node* leftRotate(Node* x) {
    Node* y = x->right;
    Node* T2 = y->left;

    // Perform rotation
    y->left = x;
    x->right = T2;

    // Update heights
    x->height = std::max(height(x->left), height(x->right)) + 1;
    y->height = std::max(height(y->left), height(y->right)) + 1;

    // Return new root
    return y;
}

// Recursive function to do a postorder traversal of the tree and print
// nodes along with their IDs
void postOrderTraversal(Node* node) {
    if (node != nullptr) {
        postOrderTraversal(node->left);
        postOrderTraversal(node->right);
        std::cout << node->key << " " << (node->left ? node->left->id : 0) << " " << (node->right ? node->right->id : 0) << std::endl;
    }
}

int main() {
    int n, key, left, right;
    std::cin >> n;
    std::vector<Node*> nodes(n+1, nullptr);

    // Read nodes
    for (int i = 1; i <= n; ++i) {
        std::cin >> key >> left >> right;
        nodes[i] = newNode(key, i);
        if (left > 0) nodes[i]->left = nodes[left];
        if (right > 0) nodes[i]->right = nodes[right];
    }

    // Update heights from bottom to top
    for (int i = n; i >= 1; --i) {
        nodes[i]->height = std::max(height(nodes[i]->left), height(nodes[i]->right)) + 1;
    }

    Node* root = nodes[1];

    // Check the balance and perform rotations
    int balance = getBalance(root);
    if (balance > 1) {
        // If right subtree is taller, check if we need a big rotation
        if (getBalance(root->right) < 0) {
            // Right-Left case
            root->right = rightRotate(root->right);
            root = leftRotate(root);
        } else {
            // Right-Right case
            root = leftRotate(root);
        }
    }

    // Output the rotated tree using post-traversal
    postOrderTraversal(root);

    // Delete all nodes to free memory
    for (Node* node : nodes) {
        delete node;
    }

    return 0;
}
