int RightRotate(int root, Node arr[]) {
  int x = arr[root].left;
  int t2 = arr[x].right;

  arr[x].right = root;
  arr[root].left = t2;

  arr[root].height = std::max(Height(arr[root].left, arr), Height(arr[root].right, arr)) + 1;
  arr[x].height = std::max(Height(arr[x].left, arr), Height(arr[x].right, arr)) + 1;

