  arr[y].height = std::max(Height(arr[y].left, arr), Height(arr[y].right, arr)) + 1;

  return y;
}

int Balance(int index, Node arr[]) {
  if (index == -1) return 0;
  return Height(arr[index].right, arr) - Height(arr[index].left, arr);
